        'kth_combination',
        "Write a Python function kth_combination(n, k, r) that returns the combination at rank r in the lexicographic listing of all k-element combinations of the integers 0..n-1, as a sorted list. n must be an int, not a bool, and at least 0; otherwise -> ValueError('bad n'). k must be an int, not a bool, and satisfy 0 <= k <= n; otherwise -> ValueError('bad k'). r must be an int, not a bool, and satisfy 0 <= r < C(n, k) where C is the binomial coefficient; otherwise -> ValueError('bad rank'). Checks run in that order: n first, then k, then r. Each combination is written as its ascending sorted list of members, and the combinations are listed in ascending lexicographic order of those lists, so for n = 4 and k = 2 the listing is [0,1], [0,2], [0,3], [1,2], [1,3], [2,3] and rank 3 is [1,2]. When k is 0 the only combination is the empty list at rank 0, so any other rank -> ValueError('bad rank'). Output ONLY the function definition.",
        'solution.py',
        'def kth_combination(n, k, r):\n    if not isinstance(n, int) or isinstance(n, bool) or n < 0:\n        raise ValueError("bad n")\n    if not isinstance(k, int) or isinstance(k, bool) or k < 0 or k > n:\n        raise ValueError("bad k")\n\n    def comb(a, b):\n        if b < 0 or b > a:\n            return 0\n        b = min(b, a - b)\n        num = 1\n        for j in range(b):\n            num = num * (a - j) // (j + 1)\n        return num\n\n    total = comb(n, k)\n    if not isinstance(r, int) or isinstance(r, bool) or r < 0 or r >= total:\n        raise ValueError("bad rank")\n    out = []\n    x = 0\n    remaining = k\n    rr = r\n    while remaining > 0:\n        c = comb(n - x - 1, remaining - 1)\n        if rr < c:\n            out.append(x)\n            remaining -= 1\n        else:\n            rr -= c\n        x += 1\n    return out\n',
        "import pytest\nfrom solution import kth_combination as f\ndef test_first(): assert f(4, 2, 0) == [0, 1]\ndef test_middle(): assert f(4, 2, 3) == [1, 2]\ndef test_last(): assert f(4, 2, 5) == [2, 3]\ndef test_five_three(): assert f(5, 3, 6) == [1, 2, 3]\ndef test_five_three_last(): assert f(5, 3, 9) == [2, 3, 4]\ndef test_k_zero(): assert f(3, 0, 0) == []\ndef test_k_equals_n(): assert f(3, 3, 0) == [0, 1, 2]\ndef test_n_zero(): assert f(0, 0, 0) == []\ndef test_bad_n():\n    with pytest.raises(ValueError) as e: f(-1, 0, 0)\n    assert str(e.value) == 'bad n'\ndef test_bool_n():\n    with pytest.raises(ValueError) as e: f(True, 1, 0)\n    assert str(e.value) == 'bad n'\ndef test_bad_k():\n    with pytest.raises(ValueError) as e: f(3, 4, 0)\n    assert str(e.value) == 'bad k'\ndef test_bool_k():\n    with pytest.raises(ValueError) as e: f(2, True, 0)\n    assert str(e.value) == 'bad k'\ndef test_bad_rank_high():\n    with pytest.raises(ValueError) as e: f(4, 2, 6)\n    assert str(e.value) == 'bad rank'\ndef test_bad_rank_neg():\n    with pytest.raises(ValueError) as e: f(4, 2, -1)\n    assert str(e.value) == 'bad rank'\ndef test_k_zero_rank_one():\n    with pytest.raises(ValueError) as e: f(3, 0, 1)\n    assert str(e.value) == 'bad rank'\n",
