        'collatz_trace',
        "Write a Python function collatz_trace(n, limit) that returns the full Collatz trajectory of n as a list, computed under a strict step budget. n must be an int, not a bool, and at least 1; otherwise -> ValueError('bad start'). limit must be an int, not a bool, and at least 0; otherwise -> ValueError('bad limit'). n is validated before limit. One step maps an even value to value // 2 and an odd value to 3 * value + 1. The trace starts with n itself and appends the value after each step, stopping once the value 1 has been appended; if n is already 1 the trace is [1] with zero steps taken, whatever the limit. Steps are transitions, so the trace always has exactly one more element than the number of steps taken. If reaching 1 would require MORE than limit steps, raise RuntimeError('limit exceeded') instead of returning; reaching 1 in exactly limit steps succeeds. The two failure kinds are distinct: validation failures are ValueError and budget exhaustion is RuntimeError. Output ONLY the function definition.",
        'solution.py',
        'def collatz_trace(n, limit):\n    if not isinstance(n, int) or isinstance(n, bool) or n < 1:\n        raise ValueError("bad start")\n    if not isinstance(limit, int) or isinstance(limit, bool) or limit < 0:\n        raise ValueError("bad limit")\n    trace = [n]\n    cur = n\n    steps = 0\n    while cur != 1:\n        if steps == limit:\n            raise RuntimeError("limit exceeded")\n        cur = cur // 2 if cur % 2 == 0 else 3 * cur + 1\n        trace.append(cur)\n        steps += 1\n    return trace\n',
        "import pytest\nfrom solution import collatz_trace as f\ndef test_one(): assert f(1, 0) == [1]\ndef test_two(): assert f(2, 1) == [2, 1]\ndef test_six(): assert f(6, 100) == [6, 3, 10, 5, 16, 8, 4, 2, 1]\ndef test_exact_budget(): assert f(6, 8) == [6, 3, 10, 5, 16, 8, 4, 2, 1]\ndef test_budget_short():\n    with pytest.raises(RuntimeError) as e: f(6, 7)\n    assert str(e.value) == 'limit exceeded'\ndef test_zero_budget():\n    with pytest.raises(RuntimeError) as e: f(2, 0)\n    assert str(e.value) == 'limit exceeded'\ndef test_seven(): assert f(7, 16) == [7, 22, 11, 34, 17, 52, 26, 13, 40, 20, 10, 5, 16, 8, 4, 2, 1]\ndef test_seven_short():\n    with pytest.raises(RuntimeError): f(7, 15)\ndef test_bad_start_zero():\n    with pytest.raises(ValueError) as e: f(0, 5)\n    assert str(e.value) == 'bad start'\ndef test_bad_start_bool():\n    with pytest.raises(ValueError) as e: f(True, 5)\n    assert str(e.value) == 'bad start'\ndef test_bad_start_float():\n    with pytest.raises(ValueError) as e: f(1.0, 5)\n    assert str(e.value) == 'bad start'\ndef test_bad_limit():\n    with pytest.raises(ValueError) as e: f(5, -1)\n    assert str(e.value) == 'bad limit'\ndef test_bad_limit_bool():\n    with pytest.raises(ValueError) as e: f(5, True)\n    assert str(e.value) == 'bad limit'\ndef test_start_before_limit():\n    with pytest.raises(ValueError) as e: f(0, -1)\n    assert str(e.value) == 'bad start'\n",
